using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        Assert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        Assert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.FormatPhoneNumber("123"));
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithNameAndComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(result, "Smith,");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDearAndTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.BuildGreeting("   "));
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_ReturnsHyphenatedSlug()
    {
        string result = _formatter.GenerateSlug("Hello World Today");

        Assert.StartsWith(result, "hello");
        Assert.EndsWith(result, "today");
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_StripsNonAlphanumeric()
    {
        string result = _formatter.GenerateSlug("C# is Great!");

        Assert.StartsWith(result, "c-");
        Assert.EndsWith(result, "great");
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.GenerateSlug("   "));
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(5m);

        Assert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_WithCents_EndsWithCentValue()
    {
        string result = _formatter.FormatCurrency(12.50m);

        Assert.EndsWith(result, ".50");
    }

    [TestMethod]
    public void FormatCurrency_FullValue_ReturnsExpectedFormat()
    {
        string result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.AreEqual("£1234.56", result);
    }
}

